create table if not exists crm_quote_cost_requests (id uuid primary key, tenant_id varchar(64) not null default 'default', quote_id uuid not null, opportunity_id uuid, customer_id uuid, status varchar(32) not null default 'REQUESTED', requested_by varchar(80) not null, requested_at timestamp with time zone not null default current_timestamp, project_manager varchar(80), labor_cost numeric(14,2) not null default 0, material_cost numeric(14,2) not null default 0, subcontract_cost numeric(14,2) not null default 0, travel_cost numeric(14,2) not null default 0, equipment_cost numeric(14,2) not null default 0, risk_reserve numeric(14,2) not null default 0, other_cost numeric(14,2) not null default 0, suggested_price numeric(14,2), cost_remark varchar(800), submitted_at timestamp with time zone, approved_by varchar(80), approved_at timestamp with time zone, approval_comment varchar(500), created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp, created_by varchar(64), updated_by varchar(64), constraint fk_quote_cost_quote foreign key(quote_id) references crm_quote_plans(id));
create index if not exists idx_quote_cost_requests_quote on crm_quote_cost_requests(quote_id,created_at);
create index if not exists idx_quote_cost_requests_status on crm_quote_cost_requests(status,requested_at);
insert into sys_permissions (id,tenant_id,code,name,module,built_in,created_at,updated_at) select '00000000-0000-4000-8000-000000002506','default','crm:quote:cost','报价成本询价','crm',true,current_timestamp,current_timestamp where not exists(select 1 from sys_permissions where tenant_id='default' and code='crm:quote:cost');
